using JH.QueryStudio.Api.DTOs;using JH.QueryStudio.Api.Services;using Microsoft.AspNetCore.Mvc;
namespace JH.QueryStudio.Api.Controllers;
[ApiController,Route("api/connections")]public sealed class ConnectionsController(IConnectionService svc):ControllerBase{[HttpGet]public Task<IEnumerable<ConnectionResponse>> Get()=>svc.ListAsync();[HttpPost]public Task<ConnectionResponse> Post(ConnectionUpsertRequest r)=>svc.SaveAsync(r);[HttpPut("{id:guid}")]public Task<ConnectionResponse> Put(Guid id,ConnectionUpsertRequest r)=>svc.SaveAsync(r,id);[HttpDelete("{id:guid}")]public Task Delete(Guid id)=>svc.DeleteAsync(id);[HttpPost("test")]public Task<bool> Test(TestConnectionRequest r,CancellationToken ct)=>svc.TestAsync(r.Connection,ct);}
[ApiController,Route("api/metadata")]public sealed class MetadataController(IMetadataService svc):ControllerBase{[HttpGet("{id:guid}")]public Task<IReadOnlyList<Domain.DbObjectNode>> Tree(Guid id,[FromQuery]string? database,CancellationToken ct)=>svc.GetTreeAsync(id,database,ct);}
[ApiController,Route("api/query")]public sealed class QueryController(IQueryExecutor exec,IQuerySecurityService sec,IConnectionService cs):ControllerBase{[HttpPost("analyze")]public async Task<IReadOnlyList<Domain.RiskFinding>> Analyze(AnalyzeQueryRequest r){var prod=false;if(r.ConnectionId is Guid id)prod=(await cs.GetAsync(id))?.Environment==Domain.EnvironmentKind.Production;return sec.Analyze(r.Sql,prod);}[HttpPost("execute")]public async Task<IActionResult> Execute(ExecuteQueryRequest r,CancellationToken ct){var p=await cs.GetAsync(r.ConnectionId);var risks=sec.Analyze(r.Sql,p?.Environment==Domain.EnvironmentKind.Production);if(risks.Count>0&&!r.ConfirmedRisk)return Conflict(new{risks,confirmation="CONFIRMAR"});return Ok(await exec.ExecuteAsync(r.ConnectionId,r.DatabaseName,r.Sql,r.MaxRows,ct));}}
[ApiController,Route("api/history")]public sealed class HistoryController(IHistoryService svc):ControllerBase{[HttpGet]public Task<IEnumerable<Domain.QueryHistory>> Get()=>svc.ListAsync();}
[ApiController,Route("api/snippets")]public sealed class SnippetsController(ISnippetService svc):ControllerBase{[HttpGet]public IReadOnlyList<Domain.SqlSnippet> Get()=>svc.BuiltIns();}
